var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"휴…. 이걸로 일단 한숨 돌릴 수 있겠어.","JPN":"ふう……これで一息つける。","ENG":"Phew... That's one thing off my list.","TWN":"呼…這樣應該可以稍微喘口氣吧。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아직 시간 남았으니까 조금 쉬었다가……","JPN":"まだ時間があるし、ちょっと休んでから……","ENG":"There's still time left, so maybe I'll rest a little–","TWN":"還有點時間，先休息一下再……"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":" 음?","JPN":" うん？","ENG":" Hmm?","TWN":"嗯？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NPC","text":{"KOREA":"이사장님~","JPN":"理事長～","ENG":"Ms. Chairwoman!","TWN":"理事長～"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"이사장님~ 트릭 오어 트릿!","JPN":"理事長～トリック・オア・トリート！","ENG":"Ms. Chairwoman! Trick or treat!","TWN":"理事長～不給糖就搗蛋！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"저번에 할로윈날에 찾아오면 과자 준다고 하셔서 찾아왔어요!","JPN":"この前、ハロウィンの日に来たらお菓子くれるって言ってたから来ました！","ENG":"You promised to give us snacks this Halloween, so we're here!","TWN":"上次你說萬聖節的時候來找你的話，你會給我們糖果喔！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"얘들아. 갑자기 들어가면 실례잖아.","JPN":"ちょっと。いきなり入るなんて失礼でしょ。","ENG":"Sky, it's rude to barge in like that.","TWN":"你們這樣突然闖進去是很沒禮貌的喔。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"죄송해요. 많이 놀라셨죠?","JPN":"ごめんなさい。驚かれましたよね？。","ENG":"I'm sorry. Did we startle you?","TWN":"理事長對不起，嚇到你了吧？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"괜찮아. 편하게 놀러 오라고 했던 건 나인걸?","JPN":"大丈夫よ。気兼ねなく遊びに来てって言ったのは私なんだから。","ENG":"It's fine. I'm the one who told you that you're welcome anytime.","TWN":"沒事，是我說你們可以來這裡玩的。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"어디 보자… 너희들이 좋아할 만한 과자는…….","JPN":"それじゃあ……あなたたちが好きそうなお菓子は……","ENG":"Now, lemme see here... What would you girls like...","TWN":"我看看喔…你們會喜歡的糖果是……"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저기… 일하시는데 정말 괜찮을까요?","JPN":"あの……お仕事してるのに、本当に大丈夫なんですか？","ENG":"Uh... are you sure it's okay while you're working?","TWN":"理事長…真的沒關係嗎？你不是在工作嗎？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"후후후… 안 괜찮으셔도 괜찮습니다.","JPN":"ふふふ……大丈夫じゃなくても大丈夫なのです。","ENG":"Fu fu fu... It's okay even if you're not.","TWN":"呵呵呵…有關係也沒關係。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"마침 새로 개발한 10초 만에 피로회복을 사용해 볼 때가 온 것 같군요!","JPN":"まさに新しく開発した、「10秒で疲労回復くん」の出番みたいですね！","ENG":"I think the time has come to test my newly developed \\"10-second Fatigue Relief!\\"","TWN":"正好我想試試看我新開發的10秒內即刻恢復效果如何！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"히어로는 항상 피곤할 테니까, 이런 기계도 유용하지 않을까 했거든요.","JPN":"ヒーローはいつもお疲れだろうから、こんな機械も役立つはずでは？　と思ったんです。","ENG":"Heroes are always exhausted, so I thought a device like this will come in handy.","TWN":"英雄常常都很累，這個機器應該會派上用場吧！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"안 돼. 그거 예전에 스카이가 졸고 있을 때 빼고 한 번도 안 써본 거잖아.","JPN":"ダメ。それ、この前スカイが居眠りしてた時以外、一度も使ったことないでしょ？","ENG":"No. You used that on Sky when she was dozing off and never used it again.","TWN":"不可以，那個只有之前在絲凱打瞌睡的時候測試過一次而已。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"자, 어서 나가자 얘들아.","JPN":"はい、みんな。早く出よう。","ENG":"Now, let's stop bothering her, girls.","TWN":"我們快點出去吧。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"너희들 그거 아니? 이사장실에 함부로 들어온 학생들은 모두 어떻게 되었는지.","JPN":"あなたたち、知ってる？　理事長室に許可もなく入ってきた生徒たちが、どうなったのかを。","ENG":"Don't you know what happens to kids that barge into the chairwoman's office?","TWN":"你們知道嗎？隨便闖入理事長辦公室的學生會有什麼下場？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"내가 대접하는 과자를 마음껏 먹을 때까지 단 한 사람도 빠져나가지 못했단다.","JPN":"私が出すお菓子をお腹いっぱい食べるまで、誰もここから出られなかったのよ。","ENG":"None of them could leave until they were completely full from all the snacks I served.","TWN":"必須要把我招待的餅乾全部吃完才可以離開。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"자, 어서 앉으렴. 이번 신상품인데 이 초코 바닐라 밀페유부터 먹어볼래?","JPN":"はい、早く座りなさい。新商品なんだけど、このチョコバニラミルフィーユから食べてみる？","ENG":"Now, sit down. Why don't you all try the new chocolate vanilla pastry?","TWN":"都快坐下，這次有新產品喔。從這個香草巧克力千層派開始吃嗎？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저, 정말요?","JPN":"ほ、本当ですか？","ENG":"R-really?","TWN":"真，真的嗎？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"우와아~ 잘 먹겠습니다!","JPN":"うわあ～いただきます！","ENG":"Wow! Thank you!","TWN":"哇～～謝謝理事長！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"음~ 정말 맛있어요!","JPN":"う～ん、とっても美味しいです！","ENG":"Mm...! It's so delicious!","TWN":"嗯～～好好吃喔！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"보통 단맛은 계속 먹다 보면 물리기도 하는데 이런 건 처음이야.","JPN":"甘いものは食べてると飽きるもんだけど、こんなのは初めてだ。","ENG":"I usually get sick of eating sweet things after a while, but this is a first.","TWN":"通常甜的東西吃多就會膩，第一次吃到這種不會膩的欸。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"세상의 모든 과자를 다 가지고 있다는 소문은 역시 사실이었네요.","JPN":"世界中のお菓子がここにあるってウワサは、やっぱり本当だったんですね。","ENG":"The rumors were true about how you have all the world's snacks.","TWN":"傳言說理事長有世界各國的餅乾，看來是真的！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"후훗, 친구들이 자주 보내주거든.","JPN":"ふふっ、友だちがよく送ってくれるの。","ENG":"Ha ha. My friends send them to me frequently.","TWN":"呵呵，因為朋友常常送給我啦。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"너희들이 많이 먹어줘서 정말 기뻐. 할로윈이 아니더라도 자주 찾아오렴.","JPN":"あなたたちがたくさん食べてくれて本当に嬉しいわ。ハロウィンじゃなくても、もっと遊びに来なさい。","ENG":"I'm glad to see that you're enjoying them. Come visit more often even when it's not Halloween.","TWN":"看你們吃得開心，我也很開心。就算不是萬聖節，也可以常來喔。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};